#include <stdio.h>
#include <string.h>

int minCut(char* s) {
    int n = strlen(s);
    int dp[n];
    for (int i = 0; i < n; i++) {
        dp[i] = i;
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= i; j++) {
            if (isPalindrome(s, j, i)) {
                if (j == 0) {
                    dp[i] = 0;
                } else if (dp[j - 1] + 1 < dp[i]) {
                    dp[i] = dp[j - 1] + 1;
                }
            }
        }
    }
    return dp[n - 1];
}

int isPalindrome(char* s, int start, int end) {
    while (start < end) {
        if (s[start] != s[end])
            return 0;
        start++;
        end--;
    }
    return 1;
}

